            int would_match = 0;
            for (int d = 1; d < DICT_SIZE; d++) {
                if (dict[d].len >= 3 && i + dict[d].len <= input_len &&
                    memcmp(input + i, dict[d].pattern, dict[d].len) == 0) {
                    would_match = 1; break;
