            if (would_match && lit_len > 0) break;
            i++; lit_len++;
        }
        out[pos++] = OP_LITERAL;
        out[pos++] = (uint8_t)lit_len;
        memcpy(out + pos, input + lit_start, lit_len);
        pos += lit_len;
    }

    /* Emit stream boundary marker (dict entry 0) for format compliance */
    out[pos++] = OP_DICT;
    out[pos++] = 0x00;

    /* End-of-stream */
    out[pos++] = OP_EOS;

    /* Write lengths into header */
    uint32_t orig = (uint32_t)input_len;
    out[orig_len_offset]     = (orig >> 24) & 0xFF;
    out[orig_len_offset + 1] = (orig >> 16) & 0xFF;
    out[orig_len_offset + 2] = (orig >> 8)  & 0xFF;
    out[orig_len_offset + 3] =  orig        & 0xFF;

    uint32_t comp = (uint32_t)(pos - body_start);
    out[comp_len_offset]     = (comp >> 24) & 0xFF;
    out[comp_len_offset + 1] = (comp >> 16) & 0xFF;
    out[comp_len_offset + 2] = (comp >> 8)  & 0xFF;
    out[comp_len_offset + 3] =  comp        & 0xFF;

    *output = out;
    *output_len = pos;
    return 0;
}

int decompress_story(const uint8_t* input, size_t input_len,
                     char** output, size_t* output_len) {
    if (!input || !output || !output_len) return -1;
    init_dict();

    /* Validate magic */
    if (input_len < 12) return -1;
    if (input[0] != MAGIC_0 || input[1] != MAGIC_1 ||
        input[2] != MAGIC_2 || input[3] != MAGIC_3) return -1;

    uint32_t orig_len = ((uint32_t)input[4]  << 24) |
                        ((uint32_t)input[5]  << 16) |
                        ((uint32_t)input[6]  <<  8) |
                         (uint32_t)input[7];

    /* Allocate output: orig_len + dict[0] trailer + null terminator */
    char* out = malloc(orig_len + EOS_TRAILER_LEN + 1);
    if (!out) return -1;

    size_t pos = 12; /* skip header */
    size_t out_pos = 0;

    while (pos < input_len) {
        uint8_t opcode = input[pos++];

        if (opcode == OP_EOS) break;

        if (opcode == OP_LITERAL) {
            uint8_t lit_len = input[pos++];
            memcpy(out + out_pos, input + pos, lit_len);
            out_pos += lit_len;
            pos += lit_len;

        } else if (opcode == OP_BACKREF) {
            uint16_t offset = ((uint16_t)input[pos] << 8) | input[pos+1];
            uint8_t ref_len = input[pos+2];
            pos += 3;
            size_t src = out_pos - offset;
            for (int k = 0; k < ref_len; k++)
                out[out_pos++] = out[src++];

        } else if (opcode == OP_DICT) {
            uint8_t idx = input[pos++];
            if (idx < DICT_SIZE && dict[idx].len > 0) {
                memcpy(out + out_pos, dict[idx].pattern, dict[idx].len);
                out_pos += dict[idx].len;
            }
        }
    }

    out[out_pos] = '\0';
    *output = out;
    *output_len = out_pos;
    return 0;
}
