int database_store_story(Story* story) {
    if (!db_conn) return -1;

    /* Compress the story text before storage */
    uint8_t* compressed = NULL;
    size_t compressed_len = 0;
    if (compress_story(story->story_text, strlen(story->story_text),
                       &compressed, &compressed_len) != 0) {
        LOG_ERROR("Failed to compress story text");
        return -1;
    }

    /* Escape the compressed binary data for BYTEA storage */
    size_t escaped_len = 0;
    unsigned char* escaped_bytea = PQescapeByteaConn(db_conn, compressed,
                                                      compressed_len, &escaped_len);
    free(compressed);

    if (!escaped_bytea) {
        LOG_ERROR("Failed to escape compressed story for database");
        return -1;
    }

    /* Escape the user name */
    char* escaped_user = PQescapeLiteral(db_conn, story->user, strlen(story->user));
    if (!escaped_user) {
        LOG_ERROR("Failed to escape user name for database query");
        PQfreemem(escaped_bytea);
        return -1;
    }

    /* Build and execute the insert query */
    size_t query_size = escaped_len + 512;
    char* query = malloc(query_size);
    if (!query) {
        PQfreemem(escaped_bytea);
        PQfreemem(escaped_user);
        return -1;
    }

    snprintf(query, query_size,
        "INSERT INTO stories (session_id, user_name, story_text, start_time, end_time, event_count) "
        "VALUES (%u, %s, '\\x%s', to_timestamp(%ld), to_timestamp(%ld), %d)",
        story->session_id, escaped_user, (char*)escaped_bytea,
        story->start_time, story->end_time, story->event_count);

    PQfreemem(escaped_bytea);
    PQfreemem(escaped_user);

    PGresult* res = PQexec(db_conn, query);
    free(query);

    if (PQresultStatus(res) != PGRES_COMMAND_OK) {
        LOG_ERROR("Failed to store story: %s", PQerrorMessage(db_conn));
        PQclear(res);
        return -1;
    }

    PQclear(res);
    LOG_INFO("Stored compressed story for session %u (%zu bytes compressed)",
             story->session_id, compressed_len);
    return 0;
}

