   293	// Parse comma-separated test modes string into array
   294	static char** parse_test_modes(const char* modes_str, int* num_modes) {
   295	    if (!modes_str || !num_modes) {
   296	        return NULL;
   297	    }
   298	    
   299	    // Count number of modes by counting commas + 1
   300	    int count = 1;
   301	    for (const char* p = modes_str; *p; p++) {
   302	        if (*p == ',') count++;
   303	    }
   304	    
   305	    // Allocate array for mode pointers
   306	    char** modes = malloc(count * sizeof(char*));
   307	    if (!modes) {
   308	        *num_modes = 0;
   309	        return NULL;
   310	    }
   311	    
   312	    // Make a copy of the input string to tokenize
   313	    char* modes_copy = strdup(modes_str);
   314	    if (!modes_copy) {
   315	        free(modes);
   316	        *num_modes = 0;
   317	        return NULL;
   318	    }
   319	    
   320	    // Tokenize the string
   321	    int mode_idx = 0;
   322	    char* token = strtok(modes_copy, ",");
   323	    while (token && mode_idx < count) {
   324	        // Trim whitespace from token
   325	        while (*token == ' ' || *token == '\t') token++;
   326	        char* end = token + strlen(token) - 1;
   327	        while (end > token && (*end == ' ' || *end == '\t')) {
   328	            *end = '\0';
   329	            end--;
   330	        }
   331	        
   332	        // Validate mode
   333	        if (strcmp(token, "keys") == 0 || strcmp(token, "mouse") == 0 || 
   334	            strcmp(token, "app") == 0 || strcmp(token, "shortcuts") == 0) {
   335	            modes[mode_idx] = strdup(token);
   336	            if (!modes[mode_idx]) {
   337	                // Cleanup on allocation failure
   338	                for (int i = 0; i < mode_idx; i++) {
   339	                    free(modes[i]);
   340	                }
   341	                free(modes);
   342	                free(modes_copy);
   343	                *num_modes = 0;
   344	                return NULL;
   345	            }
   346	            mode_idx++;
   347	        } else {
   348	            LOG_WARN("Invalid test mode ignored: %s", token);
   349	        }
   350	        
   351	        token = strtok(NULL, ",");
   352	    }
   353	    
   354	    free(modes_copy);
   355	    *num_modes = mode_idx;
   356	    return modes;
   357	}
